// Import Field datas from txt files generated by Lumerical FDTD Solutions
//Local software path
var path = UserSetting.SampleCodeDir;
// Import datas from txt files generated by Lumerical FDTD Solutions
var Re_Ex = Import.Txt2MatrixD(filePath:path+@"\ImportExportFiles\_Re_Ex.txt",columnSeparator:' ',startLine:729, endLine:1090);
var Im_Ex = Import.Txt2MatrixD(filePath:path+@"\ImportExportFiles\_Im_Ex.txt",columnSeparator:' ',startLine:729, endLine:1090);

Printer.Write($"Re_Ex.Rows = {Re_Ex.Rows}; Re_Ex.Cols = {Re_Ex.Cols}");
Printer.Write($"Im_Ex.Rows = {Im_Ex.Rows}; Im_Ey.Cols = {Im_Ex.Cols}");

//VFrame.CreateShow(Re_Ex,title:"Re_Ex");
//VFrame.CreateShow(Im_Ex,title:"Im_Ex");

var Ex = VMath.Construct(Re_Ex, Im_Ex);

// sampling grid information
var grid = new GridInfo2D(rows: Re_Ex.Rows, cols: Re_Ex.Cols, spacingY: 6.944E-8, spacingX: 6.944E-8);

var wavelength = 6.6E-7;
var v = new ScalarField(wavelength: wavelength, n: Complex.One, grid, Ex);

// input display
VFrame.CreateShow(values: v.Field, grid: v.Grid, ComplexPart.Argument ,Options.PlotColormap.Magma,
    title: "Argument of Input Ex " + v.Domain.ToString(), xLabel: "x [m]", yLabel: "y [m]");
VFrame.CreateShow(values: v.Field, grid: v.Grid, ComplexPart.Magnitude ,Options.PlotColormap.Magma,
    title: "Magnitude of Input Ex " + v.Domain.ToString(), xLabel: "x [m]", yLabel: "y [m]");
// propagate by distance d
var d = 100E-6; // 100 um 
v.Propagate(d: d, targetDomain: ModelingDomain.Spatial); // this method calls SPW internally

// output display
VFrame.CreateShow(values: v.Field, grid: v.Grid, ComplexPart.Argument, Options.PlotColormap.Magma,
    title: "Argument of Propagated Ex " + v.Domain.ToString(), xLabel: "x [m]", yLabel: "y [m]");
    VFrame.CreateShow(values: v.Field, grid: v.Grid, ComplexPart.Magnitude, Options.PlotColormap.Magma,
    title: "Magnitude of Propagated Ex " + v.Domain.ToString(), xLabel: "x [m]", yLabel: "y [m]");

